#nullable enable // autogenerated
using System;
using System.Collections.Generic;
using System.Text.RegularExpressions;
using MVZ2.Managers;
using MVZ2.Metas;
using PVZEngine;


namespace MVZ2.Almanacs
{
    public class DescriptionPropReplacer
    {

        public DescriptionPropReplacer(MainManager mainManager)
        {
            main = mainManager;
        }

        public string Replace(string description, AlmanacVariableContext context)
        {
            if (string.IsNullOrEmpty(description))
                return description;

            return PropRegex.Replace(description, m => ReplaceMatch(m, context));
        }

        private string ReplaceMatch(Match match, AlmanacVariableContext context)
        {
            // 获取可选属性，应用默认值
            var variable = GetMatchVariable(match, context);
            if (variable == null) // 变量不存在。
                return match.Value;
            return variable.GetValueString(context);
        }
        private AlmanacVariable? GetMatchVariable(Match match, AlmanacVariableContext context)
        {
            string attrs = match.Groups[1].Value;
            var props = ParseAttributes(attrs);

            if (props.TryGetValue("local", out var localName) && !string.IsNullOrEmpty(localName))
            {
                return context.currentAlmanacEntry.GetLocalVariable(localName);
            }
            else if (props.TryGetValue("id", out var idString) && NamespaceID.TryParse(idString, main.BuiltinNamespace, out var parsed))
            {
                return context.main.ResourceManager.GetAlmanacGlobalVariable(parsed);
            }
            return null;
        }

        /// <summary>
        /// 将属性字符串解析为字典，支持双引号和单引号，键值对之间空白分隔
        /// 示例：name="abc" multiplier='0.5' target=xyz
        /// </summary>
        private Dictionary<string, string> ParseAttributes(string attrString)
        {
            var dict = new Dictionary<string, string>(StringComparer.OrdinalIgnoreCase);
            // 正则匹配 key="value" 或 key='value' 或 key=value（无引号值，不含空白）
            var attrRegex = new Regex(@"(\w+)\s*=\s*(?:""([^""]*)""|'([^']*)'|([^\s>]+))");
            var matches = attrRegex.Matches(attrString);
            foreach (Match m in matches)
            {
                string key = m.Groups[1].Value;
                string value = m.Groups[2].Success ? m.Groups[2].Value :
                               (m.Groups[3].Success ? m.Groups[3].Value :
                               m.Groups[4].Value);
                dict[key] = value;
            }
            return dict;
        }
        private MainManager main;
        private static readonly Regex PropRegex = new Regex(@"<var\s+([^>]+?)\s*/>", RegexOptions.Compiled | RegexOptions.IgnoreCase);
    }
}